library(dplyr);library(readr);dir.create("data/output",showWarnings=FALSE);w1<-read_delim("data/input/wave_one_lsype_family_background_2020.tab",delim="\t");w2<-read_delim("data/input/wave_two_lsype_family_background_2020.tab",delim="\t");w4<-read_delim("data/input/wave_four_lsype_family_background_2020.tab",delim="\t");s1<-w1%>%select(NSID,W1hiqualmum,W1hiqualdad);s2<-w2%>%select(NSID,W2hiqualmum,W2hiqualdad);s4<-w4%>%select(NSID,w4hiqualmum,w4hiqualdad);m<-s1%>%full_join(s2,by="NSID")%>%full_join(s4,by="NSID");hm<-function(x){case_when(x==-999~-2,x==-99~-3,x==-98~-3,x==-94~-8,x==-92~-9,x==-91~-1,x==-1~-8,TRUE~as.numeric(x))};ce<-function(a,b,c){n<-length(a);r<-rep(NA_real_,n);for(i in 1:n){v<-c(a[i],b[i],c[i]);p<-which(!is.na(v)&v>=1&v<=20);if(length(p)>0){r[i]<-v[p[1]]}else{nx<-which(!is.na(v)&v<0);if(length(nx)>0){r[i]<-v[nx[1]]}}};return(r)};ma<-ce(hm(m$W1hiqualmum),hm(m$W2hiqualmum),hm(m$w4hiqualmum));pa<-ce(hm(m$W1hiqualdad),hm(m$W2hiqualdad),hm(m$w4hiqualdad));cc<-function(d){case_when(d>=1&d<=4~0,d>=5&d<=17~1,d==18~2,d==19~3,d==20~4,d<0~as.numeric(d),TRUE~NA_real_)};mr<-cc(ma);pr<-cc(pa);ma[is.na(ma)]<- -3;pa[is.na(pa)]<- -3;mr[is.na(mr)]<- -3;pr[is.na(pr)]<- -3;fd<-m%>%select(NSID)%>%mutate(educma=mr,educpa=pr,educdtlma=ma,educdtlpa=pa);write_csv(fd,"data/output/cleaned_data.csv")